#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define N 300
#define Q 100000

int main() {
    int n, q, i, j, x1, y1, x2, y2, ans, a[N][N];
    scanf("%d", &n);
    for (i = 0; i < n; i++) {
        for (j = 0; j < n; j++) {
            scanf("%d", &a[i][j]);
        }
    }
    scanf("%d", &q);
    for (i = 0; i < q; i++) {
        scanf("%d %d %d %d", &x1, &y1, &x2, &y2);
        int distinct[11] = {0};
        ans = 0;
        for (j = x1 - 1; j <= x2 - 1; j++) {
            for (int k = y1 - 1; k <= y2 - 1; k++) {
                if (distinct[a[j][k]] == 0) {
                    distinct[a[j][k]] = 1;
                    ans++;
                }
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

code.C++:
#include <iostream>
#include <vector>
#include <unordered_set>

using namespace std;

const int N = 300;
const int Q = 100000;

int main() {
    int n, q, i, j, x1, y1, x2, y2, ans;
    vector<vector<int>> a(N, vector<int>(N));
    cin >> n;
    for (i = 0; i < n; i++) {
        for (j = 0; j < n; j++) {
            cin >> a[i][j];
        }
    }
    cin >> q;
    for (i = 0; i < q; i++) {
        cin >> x1 >> y1 >> x2 >> y2;
        unordered_set<int> distinct;
        ans = 0;
        for (j = x1 - 1; j <= x2 - 1; j++) {
            for (int k = y1 - 1; k <= y2 - 1; k++) {
                if (distinct.find(a[j][k]) == distinct.end()) {
                    distinct.insert(a[j][k]);
                    ans++;
                }
            }
        }
        cout << ans << endl;
    }
    return 0;
}

