import java.util.Scanner;
import java.util.HashSet;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int[][] a = new int[n][n];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                a[i][j] = sc.nextInt();
            }
        }
        int q = sc.nextInt();
        for (int i = 0; i < q; i++) {
            int x1 = sc.nextInt();
            int y1 = sc.nextInt();
            int x2 = sc.nextInt();
            int y2 = sc.nextInt();
            HashSet<Integer> distinct = new HashSet<>();
            int ans = 0;
            for (int j = x1 - 1; j <= x2 - 1; j++) {
                for (int k = y1 - 1; k <= y2 - 1; k++) {
                    if (!distinct.contains(a[j][k])) {
                        distinct.add(a[j][k]);
                        ans++;
                    }
                }
            }
            System.out.println(ans);
        }
    }
}

